  position: absolute;
  right: 10px;
  top: 10px;
  z-index: 9999;
  cursor: pointer;
}
@font-face {
  font-family: "Segoe UI";
  src: url(data:font/woff2;base64,) format("woff2");
  font-weight: normal;
  font-style: normal;
  font-display: swap;
}
@font-face {
  font-family: "Segoe UI Semilight";
  src: url(data:font/woff2;base64,) format("woff2");
  font-weight: 300;
  font-style: normal;
  font-display: swap;
}
@font-face {
  font-family: "Segoe UI Light";
  src: url(data:font/woff2;base64,) format("woff2");
  font-weight: 300;
  font-style: normal;
  font-display: swap;
}
@font-face {
  font-family: "Segoe UI Bold";
  src: url(data:font/woff2;base64,) format("woff2");
  font-weight: bold;
  font-style: normal;
  font-display: swap;
}

.bg-no-data {
  width: 100%;
  height: 100vh;
  background: #fff;
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.bg-no-data-content {
  display: flex;
  justify-content: flex-start;
}
.bg-no-data-content-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  margin-top: 15px;
  margin-left: 15px;
}
.bg-no-data-content-item img {
  width: 30px;
}
.bg-no-data-content-item span {
  font-size: 18px;
  font-weight: 600;
  color: #4f46e5;
}
.guideline {
  width: 100%;
  background-color: #f6f6f6;
  padding: 30px 10%;
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-top: 20px;
}
.divider {
  width: 100%;
  border: 0.5px solid #ccc;
}
.guideline strong {
  white-space: nowrap;
}
.guideline-content {
  padding-left: 20px;
  display: flex;
  flex-direction: column;
  gap: 5px;
}
.links-container {
  padding-left: 20px;
  display: flex;
  gap: 8px;
  align-items: center;
  font-size: 12px;
}
.guideline span {
  font-size: 18px;
  font-weight: 600;
}
.cycle-class {
  position: relative;
  padding-left: 20px;
}
.cycle-class span {
  font-weight: 500;
  font-size: 16px;
}
.cycle-class::before {
  content: "";
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 5px;
  height: 5px;
  background-color: black;
  border-radius: 50%;
}

.container-chart-setting {
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  flex: 0.4;
  display: grid;
  place-items: center;
  overflow: scroll;
  /* padding-right: 20px; */
  z-index: 9999;
}
.container-chart-ui {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  width: calc(100% - 300px);
  transition: all 0.3s ease;
}
.container-chart-component {
  width: 100%;
  display: flex;
  height: 100%;
  position: relative;
}

.container-popup-conditional {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  display: grid;
  place-items: center;
  /* background: rgba(0, 0, 0, 0.3); */
  z-index: 99999;
}
.popup-conditional {
  position: absolute;
  top: 3%;
  right: 60px;
  box-shadow: rgba(60, 64, 67, 0.3) -3px 8px 15px 5px;
  /* rgba(60, 64, 67, 0.15) 0px 8px 6px 8px; */
  background-color: white;
  width: 45%;
  height: 90%;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  border-radius: 5px;
}
.popup-conditional-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background-color: #f5f5f5;
  padding: 0px 10px 0 0px;
  gap: 10px;
}
.popup-conditional-body {
  padding: 15px;
  flex: 1;
  max-height: 0;
}
.popup-conditional-body button {
  /* margin-top: 20px; */
  width: 100%;
  border: 1px solid #ececec;
  padding: 5px 5px;
  border-radius: 5px;
  background-color: #ececec;
  color: black;
  cursor: pointer;
}
.popup-conditional-body button:hover {
  background-color: #ececec;
  color: black;
}
.popup-conditional-body-form {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.popup-conditional-body-form select {
  padding: 6px;
  border-radius: 5px;
  border: 1px solid #acabab;
  width: 30%;
  color: #605e5c;
}
.popup-conditional-body-form-gradient {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-top: 15px;
}
.popup-conditional-body-form-gradient-body {
  display: flex;
  justify-content: space-between;
}
.popup-conditional-body-form-gradient-body-content-color {
  display: flex;
  gap: 6px;
  align-items: center;
  margin-top: 10px;
}
.popup-conditional-body-form-gradient-body-content-color-select {
  padding: 6px;
  border-radius: 5px;
  border: 1px solid #acabab;
  width: 200px;
  color: #605e5c;
}
.popup-conditional-body-form-gradient-body-content-input {
  padding: 6px;
  border-radius: 2px;
  border: 1px solid #acabab;
  width: 150px;
  color: #605e5c;
  margin-top: 10px;
}
.popup-conditional-footer {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 15px 10px 10px;
}
.popup-conditional-footer button {
  padding: 3px 10px;
  border-radius: 5px;
  background-color: transparent;
  cursor: pointer;
  transition: all 0.3s ease;
}
.rules-component {
  margin-top: 10px;
  display: flex;
  flex-direction: column;
}
.rules-component-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-bottom: 10px;
}
.rules-component-header button {
  display: flex;
  align-items: center;
  justify-content: center;
  width: auto;
  gap: 5px;
  margin: 0;
}
.rule-condition {
  width: 100%;
  padding: 5px;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  align-items: center;
  gap: 5px;
}
.rule-condition-item {
  display: flex;
  align-items: center;
  gap: 10px;
}
.rule-condition-item select {
  padding: 5px;
  width: 120px;
  outline: none;
  border-radius: 2px;
  border: 1px solid #acabab;
}
.rule-condition-item input {
  padding: 5px;
  width: 70px;
  outline: none;
  border-radius: 2px;
  border: 1px solid #acabab;
}
.rule-condition-item-icon {
  display: flex;
  align-items: center;
  gap: 8px;
}
@media (max-width: 868px) {
  .rule-condition {
    grid-template-columns: repeat(2, 1fr);
  }
}
@media (max-width: 668px) {
  .rule-condition {
    grid-template-columns: repeat(1, 1fr);
  }
  .popup-conditional {
    box-shadow: rgba(60, 64, 67, 0.3) 0px 1px 2px 0px, rgba(60, 64, 67, 0.15) 0px 2px 6px 2px;
    background-color: white;
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    border-radius: 5px;
  }
}
.condition-item {
  width: 100px;
  padding: 6px 10px 7px 10px;
  /* border-radius: 8px 8px 0 0; */
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.sidebar {
  display: flex;
  flex-direction: column;
  gap: 20px;
  width: 285px;
  padding: 16px;
  /* background: #f8f9fa; */
  /* border-right: 1px solid #ddd; */
  font-family: "Inter", sans-serif;
}
.sidebar-section {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.section-title {
  font-weight: 600;
  font-size: 15px;
  color: #333;
  /* margin-bottom: 4px; */
}
.draggable-field {
  padding: 6px 10px;
  /* background: white; */
  /* border: 1px solid #ddd; */
  /* border-radius: 6px; */
  /* box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05); */
  font-size: 14px;
  cursor: grab;
}
.chart-dropdown {
  position: relative;
  display: inline-block;
  width: 100%;
}
.dropdown-toggle {
  width: 100%;
  padding: 8px 10px;
  display: flex;
  align-items: center;
  gap: 8px;
  background: #ececec;
  border: 1px solid #ececec;
  border-radius: 5px;
  cursor: pointer;
  font-size: 14px;
}
.dropdown-menu {
  margin-top: 4px;
  position: absolute;
  width: 100%;
  background: white;
  border: 1px solid #ccc;
  border-radius: 5px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
  z-index: 999;
  padding: 8px 0;
}
.dropdown-menu li {
  padding: 6px 10px;
  display: flex;
  align-items: center;
  gap: 8px;
  cursor: pointer;
}
.dropdown-menu li.active {
  background: #e3f2fd;
  font-weight: 600;
}
.dropdown-menu li:hover {
  background: #f1f1f1;
}
.dots {
  display: grid;
  grid-template-columns: repeat(2, 3px);
  gap: 1.5px;
}
.dots span {
  width: 3px;
  height: 3px;
  background: #2200fd;
  border-radius: 50%;
  display: block;
}

.icon-wrapper {
  position: relative;
  display: inline-block;
}
.hoverable-icon {
  width: 25px;
  height: 25px;
  padding: 5px;
  border-radius: 5px;
  transition: background-color 0.2s;
}
.hoverable-icon:hover {
  background-color: #74b2f8;
  cursor: pointer;
}
/* Tooltip text */
.tooltip-text {
  visibility: hidden;
  opacity: 0;
  position: absolute;
  top: 50%;
  left: -15px;
  transform: translate(-100%, -50%);
  background-color: #4590f4;
  color: white;
  padding: 5px 10px;
  border-radius: 5px;
  white-space: nowrap;
  font-size: 14px;
  transition: opacity 0.2s;
}
.tooltip-text::after {
  content: "";
  position: absolute;
  top: 50%;
  right: -10px;
  transform: translateY(-50%);
  border-width: 6px;
  border-style: solid;
  border-color: transparent transparent transparent #4590f4;
}
.icon-wrapper:hover .tooltip-text {
  visibility: visible;
  opacity: 1;
}

