  display: flex;
}
.input-form-input {
  flex: 1;
  border-radius: 5px;
  padding: 8px 8px;
  border: 1px solid #ccc;
  outline: none;
  font-size: 16px;
  color: black;
  box-sizing: border-box;
  height: 40px;
  /* width: 100%; */
